import { useState } from 'react';
import api from '../api/client';
import ToastMessage from '../components/ToastMessage';

function SOS() {
  const user = JSON.parse(localStorage.getItem('user'));
  const [location, setLocation] = useState('');
  const [msg, setMsg] = useState('');
  const [error, setError] = useState('');

  const getLocation = () => {
    if (!navigator.geolocation) return;
    navigator.geolocation.getCurrentPosition((pos) => {
      setLocation(`${pos.coords.latitude}, ${pos.coords.longitude}`);
    });
  };

  const trigger = async () => {
    setMsg('');
    setError('');
    try {
      await api.post('/sos/trigger', {
        userId: user?.id || 0,
        message: 'Emergency SOS triggered',
        location: location || 'Unknown'
      });
      setMsg('SOS alert sent successfully');
    } catch (err) {
      setError(err.response?.data?.error || 'SOS failed');
    }
  };

  return (
    <div className="container py-5 text-center">
      <h2 className="mb-4">Emergency SOS</h2>
      <button className="btn btn-danger btn-lg px-5 py-3 rounded-pill" onClick={trigger}>
        TRIGGER SOS
      </button>
      <div className="mt-4">
        <button className="btn btn-outline-secondary" onClick={getLocation}>Get Current Location</button>
      </div>
      <p className="mt-3"><strong>Location:</strong> {location || 'Not set'}</p>
      <ToastMessage message={msg} />
      <ToastMessage message={error} type="danger" />
    </div>
  );
}

export default SOS;
